import { useState } from 'react';

export default function App() {
  const [a, setA] = useState('');
  const [b, setB] = useState('');
  const [op, setOp] = useState('+');
  const [result, setResult] = useState('');

  function calculate() {
    const x = Number(a) || 0;
    const y = Number(b) || 0;
    let r;
    if (op === '+') r = x + y;
    else if (op === '-') r = x - y;
    else if (op === '*') r = x * y;
    else r = x / y;
    setResult(String(r));
  }

  return (
    <div>
      <input
        data-testid="a"
        type="number"
        value={a}
        onChange={(e) => setA(e.target.value)}
      />
      <input
        data-testid="b"
        type="number"
        value={b}
        onChange={(e) => setB(e.target.value)}
      />

      <label>
        <input
          data-testid="op-add"
          type="radio"
          name="op"
          value="+"
          checked={op === '+'}
          onChange={(e) => setOp(e.target.value)}
        />
        +
      </label>
      <label>
        <input
          data-testid="op-sub"
          type="radio"
          name="op"
          value="-"
          checked={op === '-'}
          onChange={(e) => setOp(e.target.value)}
        />
        -
      </label>
      <label>
        <input
          data-testid="op-mul"
          type="radio"
          name="op"
          value="*"
          checked={op === '*'}
          onChange={(e) => setOp(e.target.value)}
        />
        *
      </label>
      <label>
        <input
          data-testid="op-div"
          type="radio"
          name="op"
          value="/"
          checked={op === '/'}
          onChange={(e) => setOp(e.target.value)}
        />
        /
      </label>

      <button data-testid="calc" onClick={calculate}>
        Calculate
      </button>

      <div data-testid="result">{result}</div>
    </div>
  );
}

